+            "neq" | "not_equals" | "!=" => Some(ComparisonOp::NotEquals),
+            "contains" | "in" => Some(ComparisonOp::Contains),
+            "not_contains" | "not_in" => Some(ComparisonOp::NotContains),
+            "gt" | ">" => Some(ComparisonOp::GreaterThan),
